            self.lines.push(AssembledLine {
                address: start_addr,
                bytes: directive_bytes,
                source: line.to_string(),
                label,
            });
        }
        return;
    }

    // Skip if no instruction
    if instruction_part.is_empty() {
        if label.is_some() {
            self.lines.push(AssembledLine {
                address: start_addr,
                bytes: vec![],
                source: line.to_string(),
                label,
            });
        }
        return;
    }

    // Parse instruction
    let bytes = self.parse_instruction(instruction_part, line_num);

